        flags = O_WRONLY | O_CREAT | O_TRUNC;
        if (strchr(mode, '+') != NULL) {
            flags = O_RDWR | O_CREAT | O_TRUNC;
        }
    } else if (strchr(mode, 'a') != NULL) {
        flags = O_WRONLY | O_CREAT | O_APPEND;
        if (strchr(mode, '+') != NULL) {
