#!/usr/bin/env node
// MIPS32r2 (o32, little-endian) userspace interpreter for doomgeneric_mips.
// Runs the static ELF, servicing its custom syscall ABI (v0=number,
// args in a0-a3,t0,t1) which uses x86_64-style syscall numbers.
'use strict';
const fs = require('fs');

const ELF_PATH = process.argv[2] || '/app/doomgeneric_mips';

// ---------------------------------------------------------------------------
// Memory
// ---------------------------------------------------------------------------
const MEM_SIZE   = 0x41000000;      // ~1.09 GB, covers text/data/bss + stack
const STACK_TOP  = 0x41000000;
const INIT_SP    = 0x40FFFF00;      // 16-byte aligned, below top

const mem   = new ArrayBuffer(MEM_SIZE);
const u8    = new Uint8Array(mem);
const i32v  = new Int32Array(mem);   // aligned 32-bit view
const memBuf = Buffer.from(mem);     // zero-copy Node Buffer over same memory

function r8u(a){ return u8[a]; }
function r8s(a){ return (u8[a]<<24)>>24; }
function r16u(a){ return u8[a] | (u8[a+1]<<8); }
function r16s(a){ return ((u8[a] | (u8[a+1]<<8))<<16)>>16; }
function r32(a){
  if((a&3)===0) return i32v[a>>>2];
  return (u8[a] | (u8[a+1]<<8) | (u8[a+2]<<16) | (u8[a+3]<<24));
}
function w8(a,v){ u8[a]=v; }
function w16(a,v){ u8[a]=v&0xff; u8[a+1]=(v>>>8)&0xff; }
function w32(a,v){
  if((a&3)===0){ i32v[a>>>2]=v; return; }
  u8[a]=v&0xff; u8[a+1]=(v>>>8)&0xff; u8[a+2]=(v>>>16)&0xff; u8[a+3]=(v>>>24)&0xff;
}

function readCStr(a){
  let s='';
  for(;;){ const c=u8[a++]; if(c===0) break; s+=String.fromCharCode(c); }
  return s;
}

// ---------------------------------------------------------------------------
// ELF loader
// ---------------------------------------------------------------------------
function loadElf(path){
  const buf = fs.readFileSync(path);
  if(buf[0]!==0x7f||buf[1]!==0x45||buf[2]!==0x4c||buf[3]!==0x46) throw new Error('not ELF');
  const entry   = buf.readUInt32LE(0x18);
  const phoff   = buf.readUInt32LE(0x1c);
  const phentsz = buf.readUInt16LE(0x2a);
  const phnum   = buf.readUInt16LE(0x2c);
  for(let i=0;i<phnum;i++){
    const o = phoff + i*phentsz;
    const p_type   = buf.readUInt32LE(o);
    if(p_type !== 1) continue;          // PT_LOAD
    const p_offset = buf.readUInt32LE(o+4);
    const p_vaddr  = buf.readUInt32LE(o+8);
    const p_filesz = buf.readUInt32LE(o+16);
    for(let j=0;j<p_filesz;j++) u8[p_vaddr+j] = buf[p_offset+j];
    // remainder up to p_memsz stays zero (buffer is zero-initialised)
  }
  return entry;
}

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const gpr = new Int32Array(32);
let HI = 0, LO = 0;
const fbits = new Uint32Array(32);   // raw FP register bits (32-bit each)
let fcc = 0;                         // FP condition code 0

// FP conversion scratch
const fscratch = new ArrayBuffer(8);
const f32 = new Float32Array(fscratch);
const f64 = new Float64Array(fscratch);
const fu32 = new Uint32Array(fscratch);
function readS(r){ fu32[0]=fbits[r]; return f32[0]; }
function writeS(r,v){ f32[0]=v; fbits[r]=fu32[0]; }
function readD(r){ fu32[0]=fbits[r]; fu32[1]=fbits[r+1]; return f64[0]; }
function writeD(r,v){ f64[0]=v; fbits[r]=fu32[0]; fbits[r+1]=fu32[1]; }

// ---------------------------------------------------------------------------
// 64-bit multiply helpers (return via module vars)
// ---------------------------------------------------------------------------
function mul64u(a,b){
  const au=a>>>0, bu=b>>>0;
  const aL=au&0xffff, aH=au>>>16, bL=bu&0xffff, bH=bu>>>16;
  const ll=aL*bL, lh=aL*bH, hl=aH*bL, hh=aH*bH;
  const cross=(ll>>>16)+(lh&0xffff)+(hl&0xffff);
  LO=((ll&0xffff)|(cross<<16))>>>0;
  HI=(hh+(lh>>>16)+(hl>>>16)+(cross>>>16))>>>0;
}
function mul64s(a,b){
  mul64u(a,b);
  let hi=HI;
  if(a<0) hi = (hi - (b>>>0))>>>0;
  if(b<0) hi = (hi - (a>>>0))>>>0;
  HI=hi>>>0;
}

// ---------------------------------------------------------------------------
// Syscall layer
// ---------------------------------------------------------------------------
const ERRNO = { EPERM:1,ENOENT:2,ESRCH:3,EINTR:4,EIO:5,ENXIO:6,EBADF:9,EAGAIN:11,
  ENOMEM:12,EACCES:13,EFAULT:14,EBUSY:16,EEXIST:17,EXDEV:18,ENODEV:19,ENOTDIR:20,
  EISDIR:21,EINVAL:22,ENFILE:23,EMFILE:24,ENOTTY:25,EFBIG:27,ENOSPC:28,ESPIPE:29,
  EROFS:30,EMLINK:31,EPIPE:32 };
function errcode(e){ return ERRNO[e && e.code] || 22; }  // default EINVAL

const O_WRONLY=1, O_RDWR=2, O_CREAT=0o100, O_TRUNC=0o1000, O_APPEND=0o2000;

// guest fd -> {hostFd, pos}. stdio (0,1,2) handled specially.
const fdTable = new Map();

function sysOpen(pathPtr, flags, mode){
  const path = readCStr(pathPtr);
  const acc = flags & 3;
  let nf = acc; // node numeric flags share POSIX values for O_RDONLY/WRONLY/RDWR
  if(flags & O_CREAT)  nf |= fs.constants.O_CREAT;
  if(flags & O_TRUNC)  nf |= fs.constants.O_TRUNC;
  if(flags & O_APPEND) nf |= fs.constants.O_APPEND;
  try {
    const hostFd = fs.openSync(path, nf, mode & 0o777);
    let pos = 0;
    if(flags & O_APPEND){ try { pos = fs.fstatSync(hostFd).size; } catch(_){} }
    fdTable.set(hostFd, { hostFd, pos });
    return hostFd;
  } catch(e){
    return -errcode(e);
  }
}

function sysRead(fd, ptr, cnt){
  try {
    if(fd===0) return fs.readSync(0, memBuf, ptr, cnt, null);
    const ent = fdTable.get(fd);
    if(!ent) return -ERRNO.EBADF;
    const n = fs.readSync(ent.hostFd, memBuf, ptr, cnt, ent.pos);
    ent.pos += n;
    return n;
  } catch(e){ return -errcode(e); }
}

function sysWrite(fd, ptr, cnt){
  try {
    if(fd===1||fd===2||fd===0){
      return fs.writeSync(fd===0?1:fd, memBuf, ptr, cnt);
    }
    const ent = fdTable.get(fd);
    if(!ent) return -ERRNO.EBADF;
    const n = fs.writeSync(ent.hostFd, memBuf, ptr, cnt, ent.pos);
    ent.pos += n;
    return n;
  } catch(e){ return -errcode(e); }
}

function sysClose(fd){
  if(fd===0||fd===1||fd===2) return 0;
  const ent = fdTable.get(fd);
  if(!ent) return -ERRNO.EBADF;
  fdTable.delete(fd);
  try { fs.closeSync(ent.hostFd); return 0; } catch(e){ return -errcode(e); }
}

function sysLseek(fd, off, whence){
  const ent = fdTable.get(fd);
  if(!ent) return -ERRNO.EBADF;
  let base = 0;
  if(whence===1) base = ent.pos;
  else if(whence===2){ try { base = fs.fstatSync(ent.hostFd).size; } catch(e){ return -errcode(e); } }
  const np = base + off;
  if(np < 0) return -ERRNO.EINVAL;
  ent.pos = np;
  return np;
}

let timeCtr = 0;
function handleSyscall(){
  const num = gpr[2]|0;
  const a0=gpr[4]|0, a1=gpr[5]|0, a2=gpr[6]|0, a3=gpr[7]|0;
  let ret = 0;
  switch(num){
    case 0:  ret = sysRead(a0, a1>>>0, a2>>>0); break;
    case 1:  ret = sysWrite(a0, a1>>>0, a2>>>0); break;
    case 2:  ret = sysOpen(a0>>>0, a1>>>0, a2>>>0); break;
    case 3:  ret = sysClose(a0); break;
    case 8:  ret = sysLseek(a0, a1, a2); break;
    case 74: { const e=fdTable.get(a0); if(e){ try{ fs.fsyncSync(e.hostFd);}catch(_){} } ret=0; break; }
    case 82: { try { fs.renameSync(readCStr(a0>>>0), readCStr(a1>>>0)); ret=0; } catch(e){ ret=-errcode(e);} break; }
    case 83: { try { fs.mkdirSync(readCStr(a0>>>0), a1&0o777); ret=0; } catch(e){ ret=-errcode(e);} break; }
    case 87: { try { fs.unlinkSync(readCStr(a0>>>0)); ret=0; } catch(e){ ret=-errcode(e);} break; }
    case 60: flushAndExit(a0); break;                       // exit
    case 201: { const t = Math.floor(Date.now()/1000); if(a0) w32(a0>>>0, t|0); ret = t|0; break; } // time
    case 96: { if(a0){ w32(a0>>>0, (Date.now()/1000)|0); w32((a0>>>0)+4, (timeCtr++ ) ); } ret=0; break; } // gettimeofday
    case 35: ret = 0; break;                                 // nanosleep -> no-op
    default: ret = -ERRNO.EINVAL; break;
  }
  gpr[2] = ret|0;
}

function flushAndExit(code){
  process.exit(code|0);
}

// ---------------------------------------------------------------------------
// Main interpreter loop
// ---------------------------------------------------------------------------
function run(entry){
  gpr[29] = INIT_SP;    // sp
  gpr[31] = 0;          // ra sentinel
  let pc  = entry|0;
  let npc = (entry+4)|0;

  for(;;){
    if((pc>>>0) === 0 || (pc>>>0) >= MEM_SIZE){
      throw new Error('pc out of range: 0x'+(pc>>>0).toString(16));
    }
    const inst = i32v[pc>>>2] >>> 0;
    let target = -1;                 // >=0 => taken branch/jump target
    gpr[0] = 0;

    const op = inst >>> 26;
    switch(op){
      case 0x00: { // SPECIAL
        const funct = inst & 0x3f;
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31, rd=(inst>>>11)&31, sa=(inst>>>6)&31;
        switch(funct){
          case 0x00: gpr[rd] = gpr[rt] << sa; break;                     // sll
          case 0x02: {                                                  // srl / rotr
            if((inst>>>21)&1){ const s=sa; gpr[rd]= s? ((gpr[rt]>>>s)|(gpr[rt]<<(32-s))) : gpr[rt]; }
            else gpr[rd] = gpr[rt] >>> sa;
            break;
          }
          case 0x03: gpr[rd] = gpr[rt] >> sa; break;                     // sra
          case 0x04: gpr[rd] = gpr[rt] << (gpr[rs]&31); break;           // sllv
          case 0x06: {                                                  // srlv / rotrv
            const s=gpr[rs]&31;
            if((inst>>>6)&1){ gpr[rd]= s? ((gpr[rt]>>>s)|(gpr[rt]<<(32-s))) : gpr[rt]; }
            else gpr[rd] = gpr[rt] >>> s;
            break;
          }
          case 0x07: gpr[rd] = gpr[rt] >> (gpr[rs]&31); break;           // srav
          case 0x08: target = gpr[rs]|0; break;                          // jr
          case 0x09: gpr[rd===0?31:rd] = (pc+8)|0; target = gpr[rs]|0; break; // jalr
          case 0x0a: if(gpr[rt]===0) gpr[rd]=gpr[rs]; break;             // movz
          case 0x0b: if(gpr[rt]!==0) gpr[rd]=gpr[rs]; break;             // movn
          case 0x0c: handleSyscall(); break;                            // syscall
          case 0x0d: break;                                             // break -> ignore
          case 0x0f: break;                                             // sync
          case 0x10: gpr[rd]=HI|0; break;                                // mfhi
          case 0x11: HI=gpr[rs]|0; break;                               // mthi
          case 0x12: gpr[rd]=LO|0; break;                                // mflo
          case 0x13: LO=gpr[rs]|0; break;                               // mtlo
          case 0x18: mul64s(gpr[rs]|0, gpr[rt]|0); break;               // mult
          case 0x19: mul64u(gpr[rs]|0, gpr[rt]|0); break;               // multu
          case 0x1a: {                                                  // div
            const a=gpr[rs]|0, b=gpr[rt]|0;
            if(b!==0){ LO=(Math.trunc(a/b))|0; HI=(a - Math.trunc(a/b)*b)|0; }
            else { LO=0; HI=a; }
            break;
          }
          case 0x1b: {                                                  // divu
            const a=gpr[rs]>>>0, b=gpr[rt]>>>0;
            if(b!==0){ LO=(Math.floor(a/b))|0; HI=(a - Math.floor(a/b)*b)|0; }
            else { LO=0; HI=a|0; }
            break;
          }
          case 0x20: gpr[rd] = (gpr[rs]+gpr[rt])|0; break;               // add
          case 0x21: gpr[rd] = (gpr[rs]+gpr[rt])|0; break;               // addu
          case 0x22: gpr[rd] = (gpr[rs]-gpr[rt])|0; break;               // sub
          case 0x23: gpr[rd] = (gpr[rs]-gpr[rt])|0; break;               // subu
          case 0x24: gpr[rd] = gpr[rs] & gpr[rt]; break;                 // and
          case 0x25: gpr[rd] = gpr[rs] | gpr[rt]; break;                 // or
          case 0x26: gpr[rd] = gpr[rs] ^ gpr[rt]; break;                 // xor
          case 0x27: gpr[rd] = ~(gpr[rs] | gpr[rt]); break;              // nor
          case 0x2a: gpr[rd] = (gpr[rs] < gpr[rt]) ? 1 : 0; break;       // slt
          case 0x2b: gpr[rd] = ((gpr[rs]>>>0) < (gpr[rt]>>>0)) ? 1 : 0; break; // sltu
          case 0x34: break;                                             // teq -> no trap
          case 0x30: break;                                             // tge (unused)
          case 0x36: break;                                             // tne (unused)
          default: throw new Error('SPECIAL funct 0x'+funct.toString(16)+' @0x'+pc.toString(16));
        }
        break;
      }
      case 0x01: { // REGIMM
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31;
        const simm=(inst<<16)>>16;
        const tgt=(npc + (simm<<2))|0;
        switch(rt){
          case 0x00: if((gpr[rs]|0) < 0) target=tgt; break;             // bltz
          case 0x01: if((gpr[rs]|0) >= 0) target=tgt; break;            // bgez
          case 0x10: gpr[31]=(pc+8)|0; if((gpr[rs]|0) < 0) target=tgt; break; // bltzal
          case 0x11: gpr[31]=(pc+8)|0; if((gpr[rs]|0) >= 0) target=tgt; break; // bgezal
          default: throw new Error('REGIMM rt 0x'+rt.toString(16));
        }
        break;
      }
      case 0x02: target = ((npc & 0xf0000000) | ((inst & 0x3ffffff)<<2))|0; break; // j
      case 0x03: gpr[31]=(pc+8)|0; target = ((npc & 0xf0000000) | ((inst & 0x3ffffff)<<2))|0; break; // jal
      case 0x04: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; if(gpr[rs]===gpr[rt]) target=(npc+(((inst<<16)>>16)<<2))|0; break; } // beq
      case 0x05: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; if(gpr[rs]!==gpr[rt]) target=(npc+(((inst<<16)>>16)<<2))|0; break; } // bne
      case 0x06: { const rs=(inst>>>21)&31; if((gpr[rs]|0) <= 0) target=(npc+(((inst<<16)>>16)<<2))|0; break; } // blez
      case 0x07: { const rs=(inst>>>21)&31; if((gpr[rs]|0) > 0) target=(npc+(((inst<<16)>>16)<<2))|0; break; } // bgtz
      case 0x08: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=(gpr[rs]+((inst<<16)>>16))|0; break; } // addi
      case 0x09: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=(gpr[rs]+((inst<<16)>>16))|0; break; } // addiu
      case 0x0a: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=((gpr[rs]|0) < ((inst<<16)>>16))?1:0; break; } // slti
      case 0x0b: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=((gpr[rs]>>>0) < (((inst<<16)>>16)>>>0))?1:0; break; } // sltiu
      case 0x0c: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=gpr[rs] & (inst&0xffff); break; } // andi
      case 0x0d: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=gpr[rs] | (inst&0xffff); break; } // ori
      case 0x0e: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=gpr[rs] ^ (inst&0xffff); break; } // xori
      case 0x0f: { const rt=(inst>>>16)&31; gpr[rt]=(inst&0xffff)<<16; break; } // lui
      case 0x11: execCop1(inst, pc, npc, (t)=>{target=t;}); break;    // COP1
      case 0x1c: { // SPECIAL2
        const funct=inst&0x3f, rs=(inst>>>21)&31, rt=(inst>>>16)&31, rd=(inst>>>11)&31;
        if(funct===0x02){ gpr[rd]=Math.imul(gpr[rs]|0, gpr[rt]|0); }       // mul
        else if(funct===0x20){ // clz
          let x=gpr[rs]>>>0, n=0; while(n<32 && (x & 0x80000000)===0){ n++; x<<=1; } gpr[rd]=n;
        }
        else throw new Error('SPECIAL2 funct 0x'+funct.toString(16));
        break;
      }
      case 0x1f: { // SPECIAL3
        const funct=inst&0x3f, rs=(inst>>>21)&31, rt=(inst>>>16)&31;
        if(funct===0x00){ // ext
          const lsb=(inst>>>6)&31, msbd=(inst>>>11)&31, size=msbd+1;
          const mask = size>=32 ? 0xffffffff : ((1<<size)-1);
          gpr[rt] = (gpr[rs]>>>lsb) & mask;
        } else if(funct===0x04){ // ins
          const lsb=(inst>>>6)&31, msb=(inst>>>11)&31, size=msb-lsb+1;
          const m = (size>=32?0xffffffff:((1<<size)-1))<<lsb;
          gpr[rt] = (gpr[rt] & ~m) | ((gpr[rs]<<lsb) & m);
        } else if(funct===0x20){ // BSHFL
          const rd=(inst>>>11)&31, sh=(inst>>>6)&31, v=gpr[rt]>>>0;
          if(sh===0x02) gpr[rd] = (((v&0x00ff00ff)<<8) | ((v>>>8)&0x00ff00ff)); // wsbh
          else if(sh===0x10) gpr[rd] = (v<<24)>>24;   // seb
          else if(sh===0x18) gpr[rd] = (v<<16)>>16;   // seh
          else throw new Error('BSHFL sh 0x'+sh.toString(16));
        } else throw new Error('SPECIAL3 funct 0x'+funct.toString(16));
        break;
      }
      // Loads
      case 0x20: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=r8s((gpr[rs]+((inst<<16)>>16))|0); break; } // lb
      case 0x21: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=r16s((gpr[rs]+((inst<<16)>>16))|0); break; } // lh
      case 0x23: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=r32((gpr[rs]+((inst<<16)>>16))|0); break; } // lw
      case 0x24: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=r8u((gpr[rs]+((inst<<16)>>16))|0); break; } // lbu
      case 0x25: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; gpr[rt]=r16u((gpr[rs]+((inst<<16)>>16))|0); break; } // lhu
      case 0x22: { // lwl
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0;
        const o=a&3, w=r32(a&~3), sh=8*(3-o);
        gpr[rt] = (w<<sh) | (gpr[rt] & ((1<<sh)-1));
        break;
      }
      case 0x26: { // lwr
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0;
        const o=a&3, w=r32(a&~3), sh=8*o;
        gpr[rt] = (w>>>sh) | (gpr[rt] & ~(0xffffffff>>>sh));
        break;
      }
      // Stores
      case 0x28: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; w8((gpr[rs]+((inst<<16)>>16))|0, gpr[rt]&0xff); break; } // sb
      case 0x29: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; w16((gpr[rs]+((inst<<16)>>16))|0, gpr[rt]&0xffff); break; } // sh
      case 0x2b: { const rs=(inst>>>21)&31, rt=(inst>>>16)&31; w32((gpr[rs]+((inst<<16)>>16))|0, gpr[rt]|0); break; } // sw
      case 0x2a: { // swl
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0;
        const o=a&3, base=a&~3, w=r32(base), sh=8*(3-o), mask=0xffffffff>>>sh;
        w32(base, ((w & ~mask) | ((gpr[rt]>>>sh) & mask))|0);
        break;
      }
      case 0x2e: { // swr
        const rs=(inst>>>21)&31, rt=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0;
        const o=a&3, base=a&~3, w=r32(base), sh=8*o, mask=(0xffffffff<<sh)>>>0;
        w32(base, ((w & ~mask) | ((gpr[rt]<<sh) & mask))|0);
        break;
      }
      // FP loads/stores
      case 0x31: { const rs=(inst>>>21)&31, ft=(inst>>>16)&31; fbits[ft]=r32((gpr[rs]+((inst<<16)>>16))|0)>>>0; break; } // lwc1
      case 0x39: { const rs=(inst>>>21)&31, ft=(inst>>>16)&31; w32((gpr[rs]+((inst<<16)>>16))|0, fbits[ft]|0); break; } // swc1
      case 0x35: { const rs=(inst>>>21)&31, ft=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0; fbits[ft]=r32(a)>>>0; fbits[ft+1]=r32(a+4)>>>0; break; } // ldc1
      case 0x3d: { const rs=(inst>>>21)&31, ft=(inst>>>16)&31; const a=(gpr[rs]+((inst<<16)>>16))|0; w32(a, fbits[ft]|0); w32(a+4, fbits[ft+1]|0); break; } // sdc1
      default: throw new Error('opcode 0x'+op.toString(16)+' @0x'+pc.toString(16));
    }

    pc  = npc;
    npc = (target>=0) ? (target|0) : ((npc+4)|0);
  }
}

// COP1 handling; setBranch(target) taken FP branch
function execCop1(inst, pc, npc, setBranch){
  const rsF=(inst>>>21)&31;
  const ft=(inst>>>16)&31, fs=(inst>>>11)&31, fd=(inst>>>6)&31;
  const fn=inst&0x3f;
  switch(rsF){
    case 0x00: gpr[ft]=fbits[fs]|0; return;          // mfc1
    case 0x02: gpr[ft]= (fs===31 ? (fcc?0x00800000:0) : 0); return; // cfc1 (FCSR: cc bit23)
    case 0x03: gpr[ft]=fbits[fs+1]|0; return;        // mfhc1
    case 0x04: fbits[fs]=gpr[ft]>>>0; return;        // mtc1
    case 0x06: return;                               // ctc1 -> ignore
    case 0x07: fbits[fs+1]=gpr[ft]>>>0; return;      // mthc1
    case 0x08: { // BC1
      const tf=(inst>>>16)&1;
      if((fcc?1:0)===tf) setBranch((npc + (((inst<<16)>>16)<<2))|0);
      return;
    }
    case 0x10: { // single
      switch(fn){
        case 0x00: writeS(fd, readS(fs)+readS(ft)); return;
        case 0x01: writeS(fd, readS(fs)-readS(ft)); return;
        case 0x02: writeS(fd, Math.fround(readS(fs)*readS(ft))); return;
        case 0x03: writeS(fd, readS(fs)/readS(ft)); return;
        case 0x04: writeS(fd, Math.sqrt(readS(fs))); return;
        case 0x05: writeS(fd, Math.abs(readS(fs))); return;
        case 0x06: fbits[fd]=fbits[fs]; return;                 // mov.s
        case 0x07: writeS(fd, -readS(fs)); return;              // neg.s
        case 0x0c: fbits[fd]=(Math.round(readS(fs))|0)>>>0; return; // round.w.s
        case 0x0d: fbits[fd]=(Math.trunc(readS(fs))|0)>>>0; return; // trunc.w.s
        case 0x0e: fbits[fd]=(Math.ceil(readS(fs))|0)>>>0; return;  // ceil.w.s
        case 0x0f: fbits[fd]=(Math.floor(readS(fs))|0)>>>0; return; // floor.w.s
        case 0x11: { const tf=(inst>>>16)&1; if((fcc?1:0)===tf) fbits[fd]=fbits[fs]; return; } // movcf.s
        case 0x20: fbits[fd]=fbits[fs]; return;                 // cvt.s.s (nop)
        case 0x21: writeD(fd, readS(fs)); return;               // cvt.d.s
        case 0x24: fbits[fd]=(Math.trunc(readS(fs))|0)>>>0; return; // cvt.w.s
        default:
          if(fn>=0x30){ fpCompareS(fn&0xf, fs, ft); return; }   // c.cond.s
          throw new Error('cop1.s fn 0x'+fn.toString(16));
      }
    }
    case 0x11: { // double
      switch(fn){
        case 0x00: writeD(fd, readD(fs)+readD(ft)); return;
        case 0x01: writeD(fd, readD(fs)-readD(ft)); return;
        case 0x02: writeD(fd, readD(fs)*readD(ft)); return;
        case 0x03: writeD(fd, readD(fs)/readD(ft)); return;
        case 0x04: writeD(fd, Math.sqrt(readD(fs))); return;
        case 0x05: writeD(fd, Math.abs(readD(fs))); return;
        case 0x06: fbits[fd]=fbits[fs]; fbits[fd+1]=fbits[fs+1]; return; // mov.d
        case 0x07: writeD(fd, -readD(fs)); return;              // neg.d
        case 0x0c: fbits[fd]=(Math.round(readD(fs))|0)>>>0; return;
        case 0x0d: fbits[fd]=(Math.trunc(readD(fs))|0)>>>0; return; // trunc.w.d
        case 0x0e: fbits[fd]=(Math.ceil(readD(fs))|0)>>>0; return;
        case 0x0f: fbits[fd]=(Math.floor(readD(fs))|0)>>>0; return;
        case 0x11: { const tf=(inst>>>16)&1; if((fcc?1:0)===tf){ fbits[fd]=fbits[fs]; fbits[fd+1]=fbits[fs+1]; } return; } // movcf.d
        case 0x20: writeS(fd, readD(fs)); return;               // cvt.s.d
        case 0x24: fbits[fd]=(Math.trunc(readD(fs))|0)>>>0; return; // cvt.w.d
        default:
